#include <bits/stdc++.h>
using namespace std;
int main() {
    string num;
    cin >> num;
    int k;
    cin >> k;
    string res;
    for (char c : num) {
        while (k && !res.empty() && res.back() > c) {
            res.pop_back();
            k--;
        }
        res.push_back(c);
    }
    while (k--) {
        res.pop_back();
    }
    while (!res.empty() && res[0] == '0') {
        res.erase(0, 1);
    }
    cout << (res.empty() ? "0" : res) << endl;
    return 0;
}
